                                        240,
                                        551,
                                        504
                                    ],
                                    "type": "text",
                                    "content": " ，生理盐水）、治疗1组 "
                                },
                                {
                                    "bbox": [
                                        42,
                                        240,
                                        551,
                                        504
                                    ],
                                    "type": "inline_equation",
                                    "content": "(n = 10"
