                                    "bbox": [
                                        42,
                                        240,
                                        551,
                                        504
                                    ],
                                    "type": "text",
                                    "content": " ，胆宁片）、治疗2组 "
                                },
                                {
                                    "bbox": [
                                        42,
                                        240,
                                        551,
                                        504
                                    ],
                                    "type": "inline_equation",
                                    "content": "(n = 10"
                                },
                                {
